import{_ as o,o as t,c as d,a2 as a}from"./chunks/framework.BYlK8ftn.js";const p=JSON.parse('{"title":"Audio system & SFX","description":"","frontmatter":{},"headers":[],"relativePath":"guide/audio.md","filePath":"guide/audio.md","lastUpdated":1782030766000}'),s={name:"guide/audio.md"};function n(c,e,r,i,l,h){return t(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="audio-system-sfx" tabindex="-1">Audio system &amp; SFX <a class="header-anchor" href="#audio-system-sfx" aria-label="Permalink to &quot;Audio system &amp; SFX&quot;">​</a></h1><p>Korovany answers the board&#39;s &quot;audible + visible feedback for every action&quot; goal (MPG / <a href="/korovany/FLO/issues/FLO-355">FLO-355</a>) with a deliberately small, serverless audio layer. This is the audio half of the combat juice shipped alongside the visual feedback (screen-shake / hit-flash / damage numbers).</p><p>Source: <a href="./../../src/game/audio/"><code>src/game/audio/</code></a>.</p><h2 id="design-at-a-glance" tabindex="-1">Design at a glance <a class="header-anchor" href="#design-at-a-glance" aria-label="Permalink to &quot;Design at a glance&quot;">​</a></h2><ul><li><strong>Raw Web Audio, no library.</strong> One lazily-created <code>AudioContext</code>, one master <code>GainNode</code> for mute/volume, and a <code>play(name)</code> that fans a cached <code>AudioBuffer</code> to the speakers. That&#39;s the whole runtime.</li><li><strong>Event-driven, not scene-driven.</strong> The bus subscribes to the existing <a href="../../src/game/combat/damageEvents.ts"><code>damageEvents</code></a> bridge — the same one the HUD consumes for damage numbers and shake. No <code>play()</code> calls live in the Babylon scene; the scene only <em>emits</em> events.</li><li><strong>Procedurally synthesized SFX.</strong> Every sound is generated from oscillator + noise math with gain envelopes — see <a href="#why-synthesis-not-files">Why synthesis</a>.</li></ul><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Role</th></tr></thead><tbody><tr><td><a href="../../src/game/audio/synth.ts"><code>synth.ts</code></a></td><td>Pure PCM generation: <code>renderTone</code>, <code>mix</code>, <code>renderClip</code>. No Web Audio — takes a sample rate, returns <code>Float32Array</code>.</td></tr><tr><td><a href="../../src/game/audio/sfx.ts"><code>sfx.ts</code></a></td><td>The named-sound recipe registry (<code>SfxName</code> → voices) and <code>renderSfx</code>.</td></tr><tr><td><a href="../../src/game/audio/audioBus.ts"><code>audioBus.ts</code></a></td><td>The <code>AudioBus</code>: lazy context, master gain, <code>play</code>, <code>unlock</code>, mute/volume + persistence, locomotion/ambience (<code>checkFootstep</code>, <code>startZoneAmbience</code>, <code>stopAmbience</code>), and <code>ZONE_AMBIENCE</code> mapping. Exports the shared <code>audioBus</code> singleton.</td></tr><tr><td><a href="../../src/game/audio/uiCues.ts"><code>uiCues.ts</code></a></td><td>UI cue API: <code>playUiClick</code>, <code>playUiHover</code>, <code>onUiClick</code>, <code>uiHoverProps</code> — menu surfaces route through here instead of raw <code>play()</code>.</td></tr><tr><td><a href="../../src/app/useGameAudio.ts"><code>../../src/app/useGameAudio.ts</code></a></td><td>React hook that wires events → <code>play()</code>, unlocks on first gesture, and rides win/lose stings off the app phase.</td></tr><tr><td><a href="./../../src/app/AudioControls.tsx"><code>../../src/app/AudioControls.tsx</code></a></td><td>Mute toggle + volume slider embedded in the Settings panel.</td></tr></tbody></table><h2 id="event-→-sound-map" tabindex="-1">Event → sound map <a class="header-anchor" href="#event-→-sound-map" aria-label="Permalink to &quot;Event → sound map&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Game event</th><th>Source</th><th>Sound</th></tr></thead><tbody><tr><td>Enemy takes a hit</td><td><code>onDamage</code></td><td><code>hit</code> (low thud + noise transient)</td></tr><tr><td>Enemy dies</td><td><code>onKill</code></td><td><code>kill</code> (falling death sting)</td></tr><tr><td>Player takes damage</td><td><code>onShake</code> (fires only when the player is struck)</td><td><code>playerHurt</code> (harsh low buzz)</td></tr><tr><td>Player swings</td><td><code>onAttack</code> (new emitter, rising edge of the melee input)</td><td><code>attack</code> (whoosh)</td></tr><tr><td>Run won</td><td>app phase → <code>won</code></td><td><code>win</code> (ascending major triad)</td></tr><tr><td>Run lost</td><td>app phase → <code>lost</code></td><td><code>lose</code> (descending minor fall)</td></tr><tr><td>UI button press</td><td><code>playUiClick()</code> / <code>onUiClick()</code></td><td><code>uiClick</code> (tiny blip)</td></tr><tr><td>UI hover / focus</td><td><code>playUiHover()</code> / <code>uiHoverProps()</code></td><td><code>uiHover</code> (softer tick, cooldown-gated)</td></tr></tbody></table><h2 id="ui-cue-api" tabindex="-1">UI cue API <a class="header-anchor" href="#ui-cue-api" aria-label="Permalink to &quot;UI cue API&quot;">​</a></h2><p>Menu, faction picker, save manager, settings, and prosthetics shop buttons call the helpers in <a href="../../src/game/audio/uiCues.ts"><code>uiCues.ts</code></a>:</p><ul><li><strong><code>playUiClick()</code></strong> — standard press blip; use in <code>onClick</code> handlers.</li><li><strong><code>playUiHover()</code></strong> — softer focus/hover tick; rate-limited to 80 ms so keyboard focus sweeps do not spam the bus.</li><li><strong><code>onUiClick(handler?)</code></strong> — wraps a handler so the click cue always fires first.</li><li><strong><code>uiHoverProps()</code></strong> — <code>{ onMouseEnter, onFocus }</code> to spread on buttons/links.</li></ul><p>Never call <code>audioBus.play(&#39;uiClick&#39;)</code> directly from UI code — the cue API keeps naming and cooldown policy in one place.</p><h2 id="locomotion-zone-ambience" tabindex="-1">Locomotion &amp; zone ambience <a class="header-anchor" href="#locomotion-zone-ambience" aria-label="Permalink to &quot;Locomotion &amp; zone ambience&quot;">​</a></h2><p>These sounds are <strong>transform-driven</strong>, not <code>damageEvents</code>-driven, so they live as methods on the bus rather than in <code>useGameAudio</code>:</p><table tabindex="0"><thead><tr><th>Game state</th><th>Driver</th><th>Sound</th></tr></thead><tbody><tr><td>Player walking on the ground</td><td><code>audioBus.checkFootstep(...)</code> once per frame</td><td><code>footstep</code> (short low thud + tap), gated by a <code>0.4 s</code> cooldown and a <code>0.01</code>-unit movement threshold</td></tr><tr><td>In-run zone bed</td><td><code>audioBus.startZoneAmbience(zoneId)</code> / <code>stopAmbience()</code></td><td>Per-zone looped beds (see table below)</td></tr></tbody></table><p>Wiring lives in <a href="./../../src/app/App.tsx"><code>App.tsx</code></a>: a <code>requestAnimationFrame</code> loop active only while <code>phase === &#39;playing&#39;</code> reads the player transform (<code>readPlayerTransform</code>), feeds the real frame <code>dt</code> (clamped to <code>0.1 s</code> so a backgrounded tab can&#39;t burst-fire steps) into <code>checkFootstep</code>, and starts/stops the looped ambience on phase entry/exit keyed on <code>playerSlice.zoneId</code>. The footstep cooldown is advanced by <code>dt</code> (not wall-clock), so it is frame-rate independent and deterministic in tests.</p><h3 id="zone-ambience-beds" tabindex="-1">Zone ambience beds <a class="header-anchor" href="#zone-ambience-beds" aria-label="Permalink to &quot;Zone ambience beds&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Zone id</th><th>SFX name</th><th>Character</th></tr></thead><tbody><tr><td><code>forest</code></td><td><code>forestAmbience</code></td><td>Wind, crickets, low drone</td></tr><tr><td><code>human-lands</code></td><td><code>humanLandsAmbience</code></td><td>Open breeze, warm mid drone</td></tr><tr><td><code>empire</code></td><td><code>empireAmbience</code></td><td>Low march pulse (ready when the zone ships)</td></tr><tr><td><code>mountains</code></td><td><code>mountainsAmbience</code></td><td>Cold wind, high whistle (ready when the zone ships)</td></tr></tbody></table><ul><li><strong><code>checkFootstep(grounded, pos, lastPos, dt)</code></strong> — advances the step clock by <code>dt</code>; plays <code>footstep</code> when grounded, moved past the threshold, and the cooldown has elapsed. A <code>null</code> <code>lastPos</code> (first frame) only seeds timing.</li><li><strong><code>startZoneAmbience(zoneId)</code> / <code>stopAmbience()</code></strong> — idempotent start; switches tracks when the zone changes. Silent until audio is unlocked. <code>getAmbienceZoneId()</code> reports which bed is playing. <code>startAmbience()</code> remains a forest alias for older call sites.</li></ul><h2 id="autoplay-policy" tabindex="-1">Autoplay policy <a class="header-anchor" href="#autoplay-policy" aria-label="Permalink to &quot;Autoplay policy&quot;">​</a></h2><p>Browsers leave a fresh <code>AudioContext</code> <strong>suspended</strong> until a user gesture. <code>useGameAudio</code> installs one-time <code>pointerdown</code> / <code>keydown</code> listeners that call <code>audioBus.unlock()</code> (which <code>resume()</code>s the context) and then detach. Before that gesture, <code>play()</code> is a silent no-op — so there are <strong>no autoplay console warnings</strong> and no errors if a sound is requested early.</p><h2 id="settings-persistence" tabindex="-1">Settings &amp; persistence <a class="header-anchor" href="#settings-persistence" aria-label="Permalink to &quot;Settings &amp; persistence&quot;">​</a></h2><p>Mute and master volume are owned by the bus and persisted to <strong><code>localStorage</code></strong> under the key <strong><code>korovany-audio</code></strong> as <code>{ muted: boolean, volume: number }</code> (defaults <code>{ false, 0.7 }</code>, volume clamped to <code>[0, 1]</code>). The pause-menu control writes through <code>audioBus.setMuted</code> / <code>setVolume</code> and re-renders off <code>audioBus.subscribe</code>, so any surface that changes settings stays in sync. Zone beds and UI cues respect the same master gain — no separate music bus.</p><h2 id="why-synthesis-not-files" tabindex="-1">Why synthesis, not files <a class="header-anchor" href="#why-synthesis-not-files" aria-label="Permalink to &quot;Why synthesis, not files&quot;">​</a></h2><p>The task brief allowed bundled CC0 sample files (LFS). We chose procedural synthesis instead because it scores better on every decision lens that matters here:</p><ul><li><strong>Budgets are real:</strong> zero binary payload — no Git LFS objects, no extra network fetch, nothing to lazy-load.</li><li><strong>Licensing:</strong> we author every waveform, so each clip is unambiguously CC0-equivalent — the strongest possible answer to &quot;never commit non-CC0.&quot;</li><li><strong>Boring tech:</strong> it <em>is</em> raw Web Audio (oscillator/noise + envelopes); no audio library, no asset pipeline.</li><li><strong>Testable:</strong> the generators are pure functions, unit-tested without a real <code>AudioContext</code>.</li></ul><p>The buffer path is the only thing that would change if we later want recorded samples: decode a file into an <code>AudioBuffer</code> instead of synthesizing one. The bus, wiring, events, and UI stay put. (Because no audio files ship, there is no audio entry in <a href="./assets"><code>assets.md</code></a> — that catalog covers binary assets only.)</p><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><p>jsdom has no real Web Audio API, so:</p><ul><li><code>synth</code> / <code>sfx</code> are pure — assert PCM length, range, and determinism directly.</li><li><code>uiCues</code> is tested with a mocked <code>audioBus.play</code> — asserts routing and hover cooldown.</li><li><code>audioBus</code> is tested against a <strong>stubbed <code>AudioContext</code></strong> and an in-memory <code>Storage</code> double, both injected via <code>new AudioBus({ createContext, storage })</code>. Asserts routing (source → master gain → destination), mute/volume gating, buffer caching, persistence round-trip, the suspended-context no-op, zone ambience switching, and the footstep cooldown/threshold behaviour.</li></ul><p>See <a href="./testing"><code>testing.md</code></a> for the project-wide stubbing patterns.</p>',32)])])}const m=o(s,[["render",n]]);export{p as __pageData,m as default};
